          rowCnt == 0                                                            // KYU_NEW : 0 건 일 때에도 보여주는 줘야함
       )
    {
//		gridheader.innerHTML = '전자세금계산서 누락 리스트(매출)';
        gr_evid2_title.setValue("전자세금계산서 누락 리스트(매출)");

        gr_evid2.setColumnVisible("evidClsNm"           , "true");  // 증빙구분명(매출)
